function showScreen(name){ if(!state.user && name!=="account") name="account"; if(state.user && !state.activeMembership && !["temple","account"].includes(name)) name="temple"; el.screens.forEach((s)=>s.classList.toggle("active",s.id===`${name}-screen`)); el.navButtons.forEach((b)=>b.classList.toggle("active",b.dataset.screen===name)); el.nav?.classList.toggle("hidden",!state.user || name==="account"); window.scrollTo({top:0,behavior:"smooth"}); }

function renderDashboard(){ const donations=state.chanda.reduce((s,x)=>s+Number(x.amount||0),0), expenses=state.kharcha.reduce((s,x)=>s+Number(x.amount||0),0), donors=new Set(state.chanda.map((x)=>String(x.donorName||"").trim().toLowerCase()).filter(Boolean)), balance=donations-expenses; setText("#total-chanda",moneyText(donations)); setText("#total-kharcha",moneyText(expenses)); setText("#net-balance",moneyText(balance)); setText("#total-donors",donors.size); setText("#total-expenses",state.kharcha.length); setText("#report-balance",moneyText(balance)); setText("#report-income",moneyText(donations)); setText("#report-expense",moneyText(expenses)); setText("#report-people-count",String(donors.size+state.members.length)); const recent=[...state.chanda.map((x)=>({type:"income",title:x.donorName||t("member"),meta:`${fmtDate(x.date)} - ${paymentText(x.paymentMode)}`,amount:x.amount,time:dateMs(x.date)})),...state.kharcha.map((x)=>({type:"outgoing",title:x.description||t("kharcha"),meta:`${fmtDate(x.date)} - ${catText(x.category)}`,amount:x.amount,time:dateMs(x.date)}))].sort((a,b)=>b.time-a.time).slice(0,3); if(el.recent) el.recent.innerHTML=recent.length?recent.map((x)=>`<article class="activity-row"><div class="activity-icon ${x.type==="outgoing"?"outgoing":""}" aria-hidden="true"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.6" stroke-linecap="round" stroke-linejoin="round"><path d="M12 ${x.type==="outgoing"?"5v14M5 12l7 7 7-7":"19V5M5 12l7-7 7 7"}"/></svg></div><div class="activity-main"><span class="activity-title">${escapeHtml(x.title)}</span><span class="activity-meta">${x.type==="outgoing"?"Kharch (Vyay)":"Dan (Chanda)"} - ${escapeHtml(x.meta.split(" - ").pop()||x.meta)}</span></div><div class="activity-side"><strong class="activity-amount ${x.type}">${moneyText(x.amount)}</strong><span class="activity-time ${x.type==="outgoing"?"outgoing":""}">${escapeHtml(x.meta.split(" - ")[0]||"05 May")}</span></div><span class="kebab" aria-hidden="true"><svg viewBox="0 0 24 24" fill="currentColor"><circle cx="12" cy="5" r="2"/><circle cx="12" cy="12" r="2"/><circle cx="12" cy="19" r="2"/></svg></span></article>`).join(""):`<div class="empty-state">${t("noActivity")}</div>`; }
function chandaDateText(v){ const d=asDate(v); return Number.isNaN(d.getTime()) ? "-" : new Intl.DateTimeFormat("en-GB",{day:"2-digit",month:"short",year:"numeric",hour:"2-digit",minute:"2-digit",hour12:true}).format(d).replace(",",""); }
function sameDay(a,b){ return a.getFullYear()===b.getFullYear()&&a.getMonth()===b.getMonth()&&a.getDate()===b.getDate(); }
function sameMonth(a,b){ return a.getFullYear()===b.getFullYear()&&a.getMonth()===b.getMonth(); }
function donorTone(name=""){ const tones=["green","blue","amber","purple","pink"]; let n=0; for(const ch of String(name)) n+=ch.charCodeAt(0); return tones[n%tones.length]; }
function donorInitial(name=""){ const key=String(name).trim().toLowerCase(); const known={"ramesh sharma":"\u0930\u093e","sita devi":"\u0938\u093f","mohanlal agrawal":"\u092e\u094b","anil verma":"\u0905\u0902","sunita patel":"\u0938\u0941"}; if(known[key]) return known[key]; const clean=String(name).trim().split(/\s+/).filter(Boolean); return (clean[0]?.slice(0,1)||"?") + (clean[1]?.slice(0,1)||""); }
function paymentMeta(mode=""){ const raw=String(mode||"Cash"); if(/cheque/i.test(raw)) return {cls:"pay-cheque",label:"Cheque",icon:'<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="3" y="6" width="18" height="12" rx="2"/><path d="M7 12h6M16 12h2"/></svg>'}; if(/bank/i.test(raw)) return {cls:"pay-online",label:"Online (Net Banking)",icon:'<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="m3 10 9-6 9 6"/><path d="M5 10v8M9 10v8M15 10v8M19 10v8M3 18h18"/></svg>'}; if(/online|upi/i.test(raw)) return {cls:"pay-online",label:raw==="Online"?"Online (UPI)":escapeHtml(raw),icon:'<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="7" y="2" width="10" height="20" rx="2"/><path d="M11 18h2"/></svg>'}; return {cls:"pay-cash",label:"Cash",icon:'<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="3" y="7" width="18" height="12" rx="2"/><path d="M16 12h5M7 12h4"/></svg>'}; }
function renderChanda(){ const term=(el.chandaSearch?.value||"").trim().toLowerCase(); let rows=state.chanda.filter((x)=>state.chandaFilter==="all"||x.paymentMode===state.chandaFilter); if(term) rows=rows.filter((x)=>`${x.donorName||""} ${x.amount||""} ${x.paymentMode||""}`.toLowerCase().includes(term)); const now=new Date(), todayTotal=state.chanda.reduce((s,x)=>{const d=asDate(x.date); return s+(sameDay(d,now)?Number(x.amount||0):0);},0), monthTotal=state.chanda.reduce((s,x)=>{const d=asDate(x.date); return s+(sameMonth(d,now)?Number(x.amount||0):0);},0); setText("#today-chanda",moneyText(todayTotal)); setText("#month-chanda",moneyText(monthTotal)); setText("#chanda-entry-count",`Kul ${rows.length||state.chanda.length} Entries`); if(!el.chandaList) return; el.chandaList.innerHTML=rows.length?rows.map((x)=>{ const pay=paymentMeta(x.paymentMode), tone=donorTone(x.donorName), actions=canEdit()?`<details class="kebab-menu chanda-kebab"><summary class="kebab-trigger" aria-label="Entry actions"><svg viewBox="0 0 24 24" fill="currentColor"><circle cx="12" cy="5" r="2"/><circle cx="12" cy="12" r="2"/><circle cx="12" cy="19" r="2"/></svg></summary><div class="kebab-panel"><button type="button" class="kebab-item" data-action="edit" data-id="${x.id}">Edit</button><button type="button" class="kebab-item danger" data-action="delete" data-id="${x.id}">Delete</button></div></details>`:`<span class="chanda-kebab" aria-hidden="true"><svg viewBox="0 0 24 24" fill="currentColor"><circle cx="12" cy="5" r="2"/><circle cx="12" cy="12" r="2"/><circle cx="12" cy="19" r="2"/></svg></span>`; return `<article class="chanda-row"><div class="chanda-avatar tone-${tone}">${escapeHtml(donorInitial(x.donorName))}</div><div class="chanda-row-main"><p class="chanda-row-name">${escapeHtml(x.donorName||t("member"))}</p><div class="chanda-pay ${pay.cls}">${pay.icon}<span>${pay.label}</span></div><div class="chanda-row-date"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="3" y="4" width="18" height="18" rx="2"/><path d="M16 2v4M8 2v4M3 10h18"/></svg>${escapeHtml(chandaDateText(x.date))}</div></div><strong class="chanda-row-amount">${moneyText(x.amount)}</strong>${actions}</article>`; }).join(""):`<div class="empty-state">${term?t("noMatchingDonor"):t("noChanda")}</div>`; }
function kharchaDateText(v){ const d=asDate(v); return Number.isNaN(d.getTime()) ? "-" : new Intl.DateTimeFormat("en-GB",{day:"2-digit",month:"short",year:"numeric",hour:"2-digit",minute:"2-digit",hour12:true}).format(d).replace(",",""); }
function kharchaCategoryMeta(category="Other"){ const key=String(category||"Other"); const map={Material:{label:"Material",cls:"material",icon:'<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M4 8h16v11H4z"/><path d="M8 8V5h8v3M4 13h16M9 13v6M15 13v6"/></svg>'},Labour:{label:"Labour",cls:"labour",icon:'<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M6 10a6 6 0 0 1 12 0"/><path d="M4 10h16M8 10v3a4 4 0 0 0 8 0v-3M6 21a6 6 0 0 1 12 0"/></svg>'},Puja:{label:"Puja",cls:"puja",icon:'<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M12 3c3 4 4 7 0 10-4-3-3-6 0-10Z"/><path d="M4 20h16M6 16c2 2 10 2 12 0"/></svg>'},Utilities:{label:"Utilities",cls:"utilities",icon:'<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M4 14h6M10 14a4 4 0 1 0 8 0v-2M18 12h3M14 10V5M12 5h4"/></svg>'},Other:{label:"Misc",cls:"other",icon:'<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M3 7h11v11H3z"/><path d="M14 11h3l4 4v3h-7z"/><circle cx="7" cy="19" r="2"/><circle cx="17" cy="19" r="2"/></svg>'}}; return map[key]||map.Other; }
function kharchaMetaText(x){ return escapeHtml(x.note||""); }
function renderKharcha(){ const term=(el.kharchaSearch?.value||"").trim().toLowerCase(); let rows=state.kharcha.filter((x)=>state.kharchaFilter==="all"||x.category===state.kharchaFilter); if(term) rows=rows.filter((x)=>`${x.description||""} ${x.amount||""} ${x.category||""} ${x.note||""}`.toLowerCase().includes(term)); const now=new Date(), monthTotal=state.kharcha.reduce((s,x)=>{const d=asDate(x.date); return s+(sameMonth(d,now)?Number(x.amount||0):0);},0), ytd=state.kharcha.reduce((s,x)=>s+Number(x.amount||0),0); setText("#kharcha-ytd",moneyText(ytd)); setText("#kharcha-month",moneyText(monthTotal)); setText("#kharcha-entry-count",`Kul ${rows.length||state.kharcha.length} Entries`); el.kharchaFilters?.querySelectorAll("button[data-category]").forEach((b)=>b.classList.toggle("active",b.dataset.category===state.kharchaFilter)); if(!el.kharchaList) return; el.kharchaList.innerHTML=rows.length?rows.map((x)=>{ const meta=kharchaCategoryMeta(x.category), inline=meta.cls==="utilities"||meta.cls==="other", note=kharchaMetaText(x), actions=canEdit()?`<details class="kebab-menu kharcha-kebab"><summary class="kebab-trigger" aria-label="Entry actions"><svg viewBox="0 0 24 24" fill="currentColor"><circle cx="12" cy="5" r="2"/><circle cx="12" cy="12" r="2"/><circle cx="12" cy="19" r="2"/></svg></summary><div class="kebab-panel"><button type="button" class="kebab-item" data-action="edit" data-id="${x.id}">Edit</button><button type="button" class="kebab-item danger" data-action="delete" data-id="${x.id}">Delete</button></div></details>`:`<span class="kharcha-kebab" aria-hidden="true"><svg viewBox="0 0 24 24" fill="currentColor"><circle cx="12" cy="5" r="2"/><circle cx="12" cy="12" r="2"/><circle cx="12" cy="19" r="2"/></svg></span>`; return `<article class="kharcha-row"><div class="kharcha-avatar expense-${meta.cls}">${meta.icon}</div><div class="kharcha-row-main"><p class="kharcha-row-title">${escapeHtml(x.description||t("kharcha"))}${inline?`<span class="kharcha-inline-cat cat-${meta.cls}">${meta.label}</span>`:""}</p>${inline?"":`<div class="kharcha-cat cat-${meta.cls}">${meta.icon}<span>${meta.label}</span></div>`}<div class="kharcha-row-date"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="3" y="4" width="18" height="18" rx="2"/><path d="M16 2v4M8 2v4M3 10h18"/></svg>${escapeHtml(kharchaDateText(x.date))}${note?`<span class="kharcha-row-note">${note}</span>`:""}</div></div><strong class="kharcha-row-amount">${moneyText(x.amount)}</strong>${actions}</article>`; }).join(""):`<div class="empty-state">${term?t("noMatchingExpense"):t("noKharcha")}</div>`; }
function renderWorkspace(){ const active=state.activeMembership; el.workspaceBar.classList.toggle("hidden",!active); el.chandaPanel.classList.toggle("hidden",!canEdit()); el.kharchaPanel.classList.toggle("hidden",!canEdit()); el.myTemplesCard.classList.toggle("hidden",!state.memberships.length); el.activeTempleCard.classList.toggle("hidden",!active); el.membersCard.classList.toggle("hidden",!active); el.renameTempleForm.classList.toggle("hidden",!active||!isOwner()); el.requestsCard.classList.toggle("hidden",!active||!isOwner()); if(active){ el.workspaceName.textContent=active.templeName; el.workspaceRole.textContent=roleText(active.role); el.workspaceRole.dataset.role=active.role; el.workspaceId.textContent=active.templeId; el.renameTempleInput.value=active.templeName; el.workspaceLocation.textContent=active.templeLocation||""; el.workspaceLocation.classList.toggle("hidden",!active.templeLocation); el.renameLocationInput.value=active.templeLocation||""; setText("#workspace-home-location",active.templeLocation||"Workspace dashboard"); setText("#dashboard-temple-subtitle",active.templeLocation||t("workspace")); } el.templeSwitcher.innerHTML=state.memberships.map((m)=>`<button class="temple-choice ${m.templeId===active?.templeId?"active":""}" data-temple-id="${m.templeId}"><div><strong>${escapeHtml(m.templeName)}</strong><span>${escapeHtml(roleText(m.role))}</span></div></button>`).join(""); el.membersList.innerHTML=state.members.length?state.members.map((m)=>{ const owner=m.role==="owner"; const control=isOwner()&&!owner?`<div class="member-controls"><span class="role-badge" data-role="${m.role}">${escapeHtml(roleText(m.role))}</span><details class="kebab-menu"><summary class="kebab-trigger" aria-label="Member actions">ÃƒÂ¢Ã¢â‚¬Â¹Ã‚Â®</summary><div class="kebab-panel"><button type="button" class="kebab-item" data-action="set-admin" data-member-id="${m.id}">${t("makeAdmin")}</button><button type="button" class="kebab-item" data-action="set-viewer" data-member-id="${m.id}">${t("makeViewer")}</button><button type="button" class="kebab-item danger" data-action="remove-member" data-member-id="${m.id}">${t("removeMemberAction")}</button></div></details></div>`:`<span class="role-badge" data-role="${m.role}">${escapeHtml(roleText(m.role))}</span>`; return `<article class="member-row"><div><strong>${escapeHtml(m.displayName||m.email||t("member"))}</strong><span>${escapeHtml(m.email||"")}</span></div>${control}</article>`; }).join(""):`<div class="empty-state">${t("noMembers")}</div>`; el.requestsList.innerHTML=state.requests.length?state.requests.map((r)=>`<article class="member-row"><div><strong>${escapeHtml(r.displayName||r.email||"User")}</strong><span>${escapeHtml(r.email||"")}</span></div><div class="approval-actions"><button class="primary-button compact" data-action="approve" data-role="admin" data-uid="${r.uid}">${t("approveAdmin")}</button><button class="secondary-button compact" data-action="approve" data-role="viewer" data-uid="${r.uid}">${t("approveViewer")}</button><button class="icon-button delete" data-action="reject" data-uid="${r.uid}">x</button></div></article>`).join(""):`<div class="empty-state">${t("noRequests")}</div>`;  const pendingCount=isOwner()?state.requests.length:0; const bell=document.getElementById("notif-bell"), badge=document.getElementById("notif-badge"); if(bell&&badge){ bell.classList.toggle("hidden",!active||!isOwner()); badge.textContent=String(pendingCount); badge.classList.toggle("hidden",pendingCount===0); }}
